#!/usr/bin/env node
/**
 * ci/test-no-tracked-build-pii.js — keep build artifacts AND PII out of git
 *
 * Two independent failure conditions, both checked against the set of files
 * git actually TRACKS (`git ls-files`) — not the working tree, so untracked
 * scratch/build output is ignored:
 *
 *   (A) BUILD ARTIFACTS IN VERSION CONTROL — any tracked path under `dist/`,
 *       or any tracked hashed build bundle. Those are regenerated by build.mjs
 *       / vite on every Vercel push (see CLAUDE.md) and must never be committed:
 *       they go stale, bloat the repo, and — worst of all — can smuggle real
 *       customer PII into git inside a minified blob. A hashed bundle is one of:
 *         *.min-<hash>.js          (e.g. script.min-C2iBUsW7.js)
 *         *.<8+hex>.min.js         (e.g. script.f9775f9654.min.js)
 *
 *   (B) LEAKED PII IN A TRACKED TEXT SOURCE — any tracked, non-binary file
 *       whose contents match an entry on the known-leaked denylist below
 *       (the real customer record that leaked into a build blob). ENFORCED.
 *       A bare Malaysian IC *format* match `\d{6}-\d{2}-\d{4}` is reported
 *       ADVISORY-only (exit 0): the codebase legitimately uses that pattern
 *       for input masking / validation / import-template sample rows, so it
 *       would false-positive. We read the file but NEVER print the matched
 *       value — only the file path and the pattern TYPE.
 *
 * Sibling of ci/escape-grep.js / ci/a11y-grep.js: same CommonJS shape, node
 * built-ins only (plus `git` via child_process), grouped report + TOTAL.
 *
 * Unlike those advisory greps, this guard ENFORCES by default (exit 1 on any
 * tracked build artifact or denylisted-PII hit) — those are release blockers.
 * Bare IC-format hits are advisory and never fail. Pass --advisory to force
 * exit 0 (report-only) for everything.
 *
 * Usage:
 *   node ci/test-no-tracked-build-pii.js             # exit 1 if any violation
 *   node ci/test-no-tracked-build-pii.js --advisory  # report-only, exit 0
 */
'use strict';
const fs        = require('fs');
const path      = require('path');
const { execSync } = require('child_process');

const ROOT     = path.resolve(__dirname, '..');
const ADVISORY = process.argv.includes('--advisory');

// ---------------------------------------------------------------------------
// Tracked-file inventory (NUL-delimited to survive spaces/unicode in paths).
// ---------------------------------------------------------------------------
function trackedFiles() {
  let out;
  try {
    out = execSync('git ls-files -z', { cwd: ROOT, maxBuffer: 64 * 1024 * 1024 });
  } catch (e) {
    console.error('  ERROR  could not run `git ls-files`: ' + e.message);
    process.exit(2);
  }
  return out.toString('utf8').split('\0').filter(Boolean);
}

// ---------------------------------------------------------------------------
// (A) build-artifact detectors
// ---------------------------------------------------------------------------
const reDistPath      = /(^|\/)dist\//;                 // anything under dist/
const reHashedBundleA = /\.min-[^/\\]*\.js$/;           // *.min-<hash>.js
const reHashedBundleB = /\.[0-9a-f]{8,}\.min\.js$/;      // *.<8+hex>.min.js

function buildArtifactReason(p) {
  if (reDistPath.test(p))      return 'dist/ tracked';
  if (reHashedBundleA.test(p)) return 'hashed bundle (*.min-<hash>.js)';
  if (reHashedBundleB.test(p)) return 'hashed bundle (*.<hash>.min.js)';
  return null;
}

// ---------------------------------------------------------------------------
// (B) PII detectors — print TYPE only, never the matched value.
// ---------------------------------------------------------------------------
// ENFORCED: the actual leaked customer record. Any tracked file containing
// one of these fails the build.
// Built from split fragments on purpose so THIS guard file never itself
// contains the literal leaked values — otherwise, once it is tracked, the
// guard would flag its own source. The fragments are inert when apart.
const DENYLIST_PATTERNS = [
  { type: 'denylist:email', re: new RegExp(['thomas', 'chee', '@gmail\\.com'].join(''), 'i') },
  { type: 'denylist:phone', re: new RegExp('\\b' + ['0122', '034218'].join('') + '\\b') },
  { type: 'denylist:ic',    re: new RegExp('\\b' + ['740315', '04', '5427'].join('-') + '\\b') },
  { type: 'denylist:name',  re: new RegExp(['CHEE', 'CHUN', 'CHING'].join(' '), 'i') },
];
// ADVISORY only: bare IC format. Legitimately appears as an input mask /
// validation pattern / import-template sample row, so it is reported but
// never fails the build.
const FORMAT_PATTERNS = [
  { type: 'MY-IC format (NNNNNN-NN-NNNN)', re: /\b\d{6}-\d{2}-\d{4}\b/ },
];

// Binary / asset extensions we never scan for text PII.
const SKIP_EXT = new Set([
  'woff2', 'woff', 'ttf', 'otf', 'eot', 'ico',
  'png', 'jpg', 'jpeg', 'gif', 'webp', 'avif', 'svg',
  'map', 'br', 'gz', 'zip', 'pdf', 'mp4', 'mov', 'mp3',
  'xlsx', 'xls', 'pptx', 'docx',
]);

// Conservative: only skip files that are *clearly* labelled dummy/fixtures.
// We require the filename itself to advertise it (not a parent dir alone), so
// real source can never be silently exempted.
const reObviousFixture = /(^|[._-])(dummy|fixture|fixtures|sample|seed|seeds|mock|mocks|example|examples)([._-]|$)/i;

function ext(p) {
  const e = path.extname(p).toLowerCase().replace(/^\./, '');
  return e;
}

function scanPii(relPath) {
  const abs = path.join(ROOT, relPath);
  let buf;
  try {
    buf = fs.readFileSync(abs);
  } catch {
    return { deny: [], format: [] };   // unreadable (e.g. submodule) — skip
  }
  // Heuristic binary sniff: a NUL byte in the first 8KB → treat as binary.
  const head = buf.subarray(0, 8192);
  if (head.includes(0)) return { deny: [], format: [] };
  const text = buf.toString('utf8');
  const deny = [];
  const format = [];
  for (const { type, re } of DENYLIST_PATTERNS) if (re.test(text)) deny.push(type);
  for (const { type, re } of FORMAT_PATTERNS)   if (re.test(text)) format.push(type);
  return { deny, format };
}

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------
const files = trackedFiles();

const buildHits  = [];   // { file, reason }       — ENFORCED
const denyHits   = [];   // { file, types: [...] } — ENFORCED (real leaked PII)
const formatHits = [];   // { file, types: [...] } — ADVISORY (IC format only)

for (const f of files) {
  const reason = buildArtifactReason(f);
  if (reason) buildHits.push({ file: f, reason });

  if (SKIP_EXT.has(ext(f)))      continue;
  if (reObviousFixture.test(path.basename(f))) continue;
  const { deny, format } = scanPii(f);
  if (deny.length)   denyHits.push({ file: f, types: deny });
  if (format.length) formatHits.push({ file: f, types: format });
}

const A = buildHits.length;
const B = denyHits.length;
const enforced = A + B;

console.log('\ntest-no-tracked-build-pii  (git-tracked files only)');

console.log(`\n  (A) tracked build artifacts [ENFORCED]: ${A}`);
const SHOW = 40;
buildHits.slice(0, SHOW).forEach((h) => console.log(`       ${h.file}  [${h.reason}]`));
if (buildHits.length > SHOW) console.log(`       … and ${buildHits.length - SHOW} more`);

console.log(`\n  (B) tracked files with LEAKED denylist PII [ENFORCED]: ${B}`);
denyHits.forEach((h) => console.log(`       ${h.file}  [${h.types.join(', ')}]`));

console.log(`\n  (C) tracked files with bare IC FORMAT [advisory only]: ${formatHits.length}`);
formatHits.slice(0, SHOW).forEach((h) => console.log(`       ${h.file}  [${h.types.join(', ')}]`));
if (formatHits.length > SHOW) console.log(`       … and ${formatHits.length - SHOW} more`);

console.log(`\n  ENFORCED violations: ${enforced}  (A=${A} build, B=${B} leaked-PII)   advisory: ${formatHits.length}`);

if (enforced === 0) {
  console.log('  PASS  no tracked build artifacts or leaked PII'
    + (formatHits.length ? `  (${formatHits.length} advisory IC-format hit(s) — review if unexpected)` : '') + '\n');
  process.exit(0);
}
if (ADVISORY) {
  console.log('  (advisory mode — not enforcing; omit --advisory to fail)\n');
  process.exit(0);
}
console.error(`  FAIL  ${enforced} enforced violation(s): build artifacts and/or leaked PII tracked in git\n`);
process.exit(1);
